public class Solution {
    public int SimilarPairs(string[] words) {
        int res = 0;
        IDictionary<int, int> cnt = new Dictionary<int, int>();
        foreach (string word in words) {
            int state = 0;
            foreach (char c in word) {
                state |= 1 << (c - 'a');
            }
            cnt.TryAdd(state, 0);
            res += cnt[state];
            cnt[state]++;
        }
        return res;
    }
}
